local luaxml = require "luaxml"

function parse_xml_request ngx.req.read_body()
    local xml_data = ngx.req.get_body_data()
    if not xml_data then
        return nil, "No XML data found in request body"
    end

    local parser = luaxml.parser.new("string", {entity_expansion_limit=0})
    local tree, err = parser:parse(xml_data)
    if not tree then
        return nil, "Failed to parse XML: " .. (err or "unknown error")
    end

    return tree
end

function extract_data_from_xml(tree)
    -- Example extraction logic:
    -- Assuming the XML has a structure like <root><name>John</name><age>30</age></root>
    local name = tree:get_node_by_path("/root/name"):get_text()
    local age = tonumber(tree:get_node_by_path("/root/age"):get_text())
    return {name=name, age=age}
end

function handle_request()
    local xml_tree, err = parse_xml_request()
    if not xml_tree then
        ngx.status = 400
        ngx.say("Bad Request: " .. (err or "unknown error"))
        return
    end

    local data, err = extract_data_from_xml(xml_tree)
    if not data then
        ngx.status = 500
        ngx.say("Internal Server Error: " .. (err or "unknown error"))
        return
    end

    -- Process the extracted data here
    ngx.say("Received data: Name=" .. data.name .. ", Age=" .. data.age)
end

handle_request()